type FileInfo struct {
	Name     string    `json:"name"`
	Path     string    `json:"path"`
	Size     int64     `json:"size"`
	IsDir    bool      `json:"is_dir"`
	Modified time.Time `json:"modified"`
}

var rootDir string

// Auth
var (
	authPassword string
	sessions     = map[string]time.Time{}
	sessionMu    sync.RWMutex
)

const sessionCookieName = "fs_session"
const sessionMaxAge = 7 * 24 * time.Hour

func generateToken() (string, error) {
	b := make([]byte, 32)
	if _, err := rand.Read(b); err != nil {
		return "", err
	}
	return hex.EncodeToString(b), nil
}

func createSession() (string, error) {
	token, err := generateToken()
	if err != nil {
		return "", err
	}
	sessionMu.Lock()
	sessions[token] = time.Now()
	sessionMu.Unlock()
	return token, nil
}

func validSession(token string) bool {
	sessionMu.RLock()
	created, ok := sessions[token]
	sessionMu.RUnlock()
	if !ok {
		return false
	}
	if time.Since(created) > sessionMaxAge {
		sessionMu.Lock()
		delete(sessions, token)
		sessionMu.Unlock()
		return false
	}
	return true
}

func authMiddleware(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		if authPassword == "" {
			next.ServeHTTP(w, r)
			return
		}
		if r.URL.Path == "/api/login" || r.URL.Path == "/api/auth-check" {
			next.ServeHTTP(w, r)
			return
		}
		cookie, err := r.Cookie(sessionCookieName)
		if err == nil && validSession(cookie.Value) {
			next.ServeHTTP(w, r)
			return
		}
		if r.URL.Path == "/" || r.URL.Path == "/terminal" {
			serveLoginPage(w)
			return
		}
		http.Error(w, "unauthorized", http.StatusUnauthorized)
	})
}

func handleLogin(w http.ResponseWriter, r *http.Request) {
	var req struct {
		Password string `json:"password"`
	}
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		http.Error(w, "invalid request", http.StatusBadRequest)
		return
	}
	if subtle.ConstantTimeCompare([]byte(req.Password), []byte(authPassword)) != 1 {
		w.Header().Set("Content-Type", "application/json")
		w.WriteHeader(http.StatusUnauthorized)
		json.NewEncoder(w).Encode(map[string]string{"error": "wrong password"})
		return
	}
	token, err := createSession()
	if err != nil {
		http.Error(w, "internal error", http.StatusInternalServerError)
		return
	}
	http.SetCookie(w, &http.Cookie{
		Name:     sessionCookieName,
		Value:    token,
		Path:     "/",
		MaxAge:   int(sessionMaxAge.Seconds()),
		HttpOnly: true,
		SameSite: http.SameSiteLaxMode,
	})
	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(map[string]bool{"ok": true})
}

func handleLogout(w http.ResponseWriter, r *http.Request) {
	cookie, err := r.Cookie(sessionCookieName)
	if err == nil {
		sessionMu.Lock()
		delete(sessions, cookie.Value)
		sessionMu.Unlock()
	}
	http.SetCookie(w, &http.Cookie{
		Name:   sessionCookieName,
		Value:  "",
		Path:   "/",
		MaxAge: -1,
	})
	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(map[string]bool{"ok": true})
}

func handleAuthCheck(w http.ResponseWriter, r *http.Request) {
	needAuth := authPassword != ""
	authenticated := false
	if needAuth {
		cookie, err := r.Cookie(sessionCookieName)
		if err == nil {
			authenticated = validSession(cookie.Value)
		}
	}
	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(map[string]bool{
		"need_auth":     needAuth,
		"authenticated": authenticated,
	})
}

