func handleFiles(w http.ResponseWriter, r *http.Request) {
	reqPath := r.URL.Query().Get("path")
	absPath, err := safePath(rootDir, reqPath)
	if err != nil {
		http.Error(w, err.Error(), http.StatusBadRequest)
		return
	}
	info, err := os.Stat(absPath)
	if err != nil {
		http.Error(w, "not found", http.StatusNotFound)
		return
	}
	if !info.IsDir() {
		http.Error(w, "not a directory", http.StatusBadRequest)
		return
	}
	entries, err := os.ReadDir(absPath)
	if err != nil {
		http.Error(w, "read error", http.StatusInternalServerError)
		return
	}
	files := make([]FileInfo, 0, len(entries))
	for _, e := range entries {
		fi, err := e.Info()
		if err != nil {
			continue
		}
		relPath := reqPath
		if relPath == "" {
			relPath = e.Name()
		} else {
			relPath = relPath + "/" + e.Name()
		}
		files = append(files, FileInfo{
			Name:     e.Name(),
			Path:     relPath,
			Size:     fi.Size(),
			IsDir:    e.IsDir(),
			Modified: fi.ModTime(),
		})
	}
	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(files)
}

func handleUpload(w http.ResponseWriter, r *http.Request) {
	reqPath := r.URL.Query().Get("path")
	absDir, err := safePath(rootDir, reqPath)
	if err != nil {
		http.Error(w, err.Error(), http.StatusBadRequest)
		return
	}
	if err := r.ParseMultipartForm(128 << 20); err != nil {
		http.Error(w, "parse error: "+err.Error(), http.StatusBadRequest)
		return
	}
	fhs := r.MultipartForm.File["files"]
	if len(fhs) == 0 {
		http.Error(w, "no files", http.StatusBadRequest)
		return
	}
	const maxFileSize = 2 << 30 // 2 GB
	for _, fh := range fhs {
		if fh.Size > maxFileSize {
			http.Error(w, fmt.Sprintf("file %q too large (%d bytes, max %d)", fh.Filename, fh.Size, maxFileSize), http.StatusRequestEntityTooLarge)
			return
		}
		destPath, err := safePath(rootDir, filepath.Join(reqPath, fh.Filename))
		if err != nil {
			http.Error(w, err.Error(), http.StatusBadRequest)
			return
		}
		// Ensure parent directory matches expected directory
		if filepath.Dir(destPath) != absDir {
			http.Error(w, "invalid filename", http.StatusBadRequest)
			return
		}
		src, err := fh.Open()
		if err != nil {
			http.Error(w, "open error", http.StatusInternalServerError)
			return
		}
		dst, err := os.Create(destPath)
		if err != nil {
			src.Close()
			http.Error(w, "create error: "+err.Error(), http.StatusInternalServerError)
			return
		}
		_, err = io.Copy(dst, src)
		src.Close()
		dst.Close()
		if err != nil {
			http.Error(w, "write error", http.StatusInternalServerError)
			return
		}
		log.Printf("uploaded: %s (%d bytes)", destPath, fh.Size)
	}
	w.WriteHeader(http.StatusOK)
	fmt.Fprintf(w, "uploaded %d file(s)", len(fhs))
}

func handleFolderUpload(w http.ResponseWriter, r *http.Request) {
	reqPath := r.URL.Query().Get("path")
	absDir, err := safePath(rootDir, reqPath)
	if err != nil {
		http.Error(w, err.Error(), http.StatusBadRequest)
		return
	}
	if err := r.ParseMultipartForm(256 << 20); err != nil {
		http.Error(w, "parse error: "+err.Error(), http.StatusBadRequest)
		return
	}
	relativePath := r.FormValue("relativePath")
	if relativePath == "" {
		http.Error(w, "relativePath required", http.StatusBadRequest)
		return
	}
	// Security: clean and validate relativePath
	cleaned := filepath.Clean(relativePath)
	if strings.HasPrefix(cleaned, "..") || filepath.IsAbs(cleaned) {
		http.Error(w, "invalid relativePath", http.StatusBadRequest)
		return
	}
	fhs := r.MultipartForm.File["file"]
	if len(fhs) == 0 {
		http.Error(w, "no file", http.StatusBadRequest)
		return
	}
	fh := fhs[0]
	const maxFileSize = 2 << 30 // 2 GB
	if fh.Size > maxFileSize {
		http.Error(w, fmt.Sprintf("file too large (%d bytes, max %d)", fh.Size, maxFileSize), http.StatusRequestEntityTooLarge)
		return
	}
	// Build destination path: absDir + relativePath
	destPath := filepath.Join(absDir, cleaned)
	// String-level check before creating directories
	if !strings.HasPrefix(destPath, rootDir+string(filepath.Separator)) && destPath != rootDir {
		http.Error(w, "path traversal denied", http.StatusBadRequest)
		return
	}
	// Create intermediate directories
	destDir := filepath.Dir(destPath)
	if err := os.MkdirAll(destDir, 0755); err != nil {
		http.Error(w, "mkdir error: "+err.Error(), http.StatusInternalServerError)
		return
	}
	// Final symlink-aware validation
	destPath, err = safePath(rootDir, filepath.Join(reqPath, cleaned))
	if err != nil {
		http.Error(w, err.Error(), http.StatusBadRequest)
		return
	}
	src, err := fh.Open()
	if err != nil {
		http.Error(w, "open error", http.StatusInternalServerError)
		return
	}
	defer src.Close()
	dst, err := os.Create(destPath)
	if err != nil {
		http.Error(w, "create error: "+err.Error(), http.StatusInternalServerError)
		return
	}
	defer dst.Close()
	if _, err = io.Copy(dst, src); err != nil {
		http.Error(w, "write error", http.StatusInternalServerError)
		return
	}
	log.Printf("folder-upload: %s (%d bytes)", destPath, fh.Size)
	w.WriteHeader(http.StatusOK)
	fmt.Fprintf(w, "ok")
}

func handleDownload(w http.ResponseWriter, r *http.Request) {
	reqPath := r.URL.Query().Get("path")
	if reqPath == "" {
		http.Error(w, "path required", http.StatusBadRequest)
		return
	}
	absPath, err := safePath(rootDir, reqPath)
	if err != nil {
		http.Error(w, err.Error(), http.StatusBadRequest)
		return
	}
	info, err := os.Stat(absPath)
	if err != nil {
		http.Error(w, "not found", http.StatusNotFound)
		return
	}
	if info.IsDir() {
		http.Error(w, "cannot download directory", http.StatusBadRequest)
		return
	}
	w.Header().Set("Content-Disposition", fmt.Sprintf(`attachment; filename="%s"`, filepath.Base(absPath)))
	http.ServeFile(w, r, absPath)
}

func handleDelete(w http.ResponseWriter, r *http.Request) {
	var req struct {
		Path string `json:"path"`
	}
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		http.Error(w, "invalid request", http.StatusBadRequest)
		return
	}
	absPath, err := safePath(rootDir, req.Path)
	if err != nil {
		http.Error(w, err.Error(), http.StatusBadRequest)
		return
	}
	if absPath == rootDir {
		http.Error(w, "cannot delete root directory", http.StatusBadRequest)
		return
	}
	info, err := os.Stat(absPath)
	if err != nil {
		http.Error(w, "not found", http.StatusNotFound)
		return
	}
	if info.IsDir() {
		err = os.RemoveAll(absPath)
	} else {
		err = os.Remove(absPath)
	}
	if err != nil {
		http.Error(w, "delete failed: "+err.Error(), http.StatusInternalServerError)
		return
	}
	log.Printf("deleted: %s", absPath)
	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(map[string]bool{"ok": true})
}

func handleRename(w http.ResponseWriter, r *http.Request) {
	var req struct {
		OldPath string `json:"old_path"`
		NewPath string `json:"new_path"`
	}
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		http.Error(w, "invalid request", http.StatusBadRequest)
		return
	}
	oldAbs, err := safePath(rootDir, req.OldPath)
	if err != nil {
		http.Error(w, err.Error(), http.StatusBadRequest)
		return
	}
	newAbs, err := safePath(rootDir, req.NewPath)
	if err != nil {
		http.Error(w, err.Error(), http.StatusBadRequest)
		return
	}
	if oldAbs == rootDir || newAbs == rootDir {
		http.Error(w, "cannot rename root directory", http.StatusBadRequest)
		return
	}
	if err := os.Rename(oldAbs, newAbs); err != nil {
		http.Error(w, "rename failed: "+err.Error(), http.StatusInternalServerError)
		return
	}
	log.Printf("renamed: %s -> %s", oldAbs, newAbs)
	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(map[string]bool{"ok": true})
}

func handleMkdir(w http.ResponseWriter, r *http.Request) {
	var req struct {
		Path string `json:"path"`
	}
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		http.Error(w, "invalid request", http.StatusBadRequest)
		return
	}
	absPath, err := safePath(rootDir, req.Path)
	if err != nil {
		http.Error(w, err.Error(), http.StatusBadRequest)
		return
	}
	if err := os.Mkdir(absPath, 0755); err != nil {
		http.Error(w, "mkdir failed: "+err.Error(), http.StatusInternalServerError)
		return
	}
	log.Printf("mkdir: %s", absPath)
	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(map[string]bool{"ok": true})
}

func handleRead(w http.ResponseWriter, r *http.Request) {
	reqPath := r.URL.Query().Get("path")
	if reqPath == "" {
		http.Error(w, "path required", http.StatusBadRequest)
		return
	}
	absPath, err := safePath(rootDir, reqPath)
	if err != nil {
		http.Error(w, err.Error(), http.StatusBadRequest)
		return
	}
	info, err := os.Stat(absPath)
	if err != nil {
		http.Error(w, "not found", http.StatusNotFound)
		return
	}
	if info.IsDir() {
		http.Error(w, "cannot read directory", http.StatusBadRequest)
		return
	}
	if info.Size() > 10<<20 {
		http.Error(w, "file too large (>10MB)", http.StatusBadRequest)
		return
	}
	data, err := os.ReadFile(absPath)
	if err != nil {
		http.Error(w, "read error", http.StatusInternalServerError)
		return
	}
	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(map[string]string{
		"content": string(data),
		"name":    filepath.Base(absPath),
	})
}

func handleSave(w http.ResponseWriter, r *http.Request) {
	var req struct {
		Path    string `json:"path"`
		Content string `json:"content"`
	}
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		http.Error(w, "invalid request", http.StatusBadRequest)
		return
	}
	absPath, err := safePath(rootDir, req.Path)
	if err != nil {
		http.Error(w, err.Error(), http.StatusBadRequest)
		return
	}
	if absPath == rootDir {
		http.Error(w, "cannot write to root directory", http.StatusBadRequest)
		return
	}
	info, err := os.Stat(absPath)
	if err != nil {
		http.Error(w, "not found", http.StatusNotFound)
		return
	}
	if info.IsDir() {
		http.Error(w, "cannot write to directory", http.StatusBadRequest)
		return
	}
	perm := info.Mode().Perm()
	if err := os.WriteFile(absPath, []byte(req.Content), perm); err != nil {
		http.Error(w, "write error: "+err.Error(), http.StatusInternalServerError)
		return
	}
	log.Printf("saved: %s (%d bytes)", absPath, len(req.Content))
	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(map[string]bool{"ok": true})
}

func handleTerminal(w http.ResponseWriter, r *http.Request) {
	conn, err := upgrader.Upgrade(w, r, nil)
	if err != nil {
		log.Printf("websocket upgrade error: %v", err)
		return
	}

	sessionID := r.URL.Query().Get("session")

	var sess *ptySession

	if sessionID != "" {
		// Reconnect to existing session
		ptySessionsMu.Lock()
		existing, ok := ptySessions[sessionID]
		ptySessionsMu.Unlock()
		if !ok {
			conn.WriteMessage(websocket.TextMessage, []byte("\r\n\x1b[31m[会话不存在或已过期]\x1b[0m\r\n"))
			conn.Close()
			return
		}
		sess = existing
		sess.mu.Lock()
		// Disconnect old client
		if sess.conn != nil {
			sess.conn.WriteMessage(websocket.TextMessage, []byte("\r\n\x1b[33m[会话已在其他窗口打开]\x1b[0m\r\n"))
			sess.conn.Close()
		}
		sess.conn = conn
		sess.lastActivity = time.Now()
		// Replay buffer
		if len(sess.buffer) > 0 {
			conn.WriteMessage(websocket.BinaryMessage, sess.buffer)
		}
		sess.mu.Unlock()
		// Send session ID confirmation
		conn.WriteMessage(websocket.TextMessage, []byte("session:"+sess.id))
	} else {
		// Create new session
		cmd := exec.Command("/bin/bash")
		cmd.Dir = rootDir
		cmd.Env = append(os.Environ(), "TERM=xterm-256color")

		ptmx, err := pty.Start(cmd)
		if err != nil {
			log.Printf("pty start error: %v", err)
			conn.Close()
			return
		}

		num := atomic.AddInt64(&ptySessionCounter, 1)
		sess = &ptySession{
			id:           uuid.New().String(),
			name:         fmt.Sprintf("终端 %d", num),
			createdAt:    time.Now(),
			lastActivity: time.Now(),
			ptmx:         ptmx,
			cmd:          cmd,
			conn:         conn,
			buffer:       make([]byte, 0, 102400),
			bufLimit:     102400, // 100KB
		}

		ptySessionsMu.Lock()
		ptySessions[sess.id] = sess
		ptySessionsMu.Unlock()

		// Send session ID to client
		conn.WriteMessage(websocket.TextMessage, []byte("session:"+sess.id))

		// PTY → WebSocket (runs for lifetime of PTY)
		go func() {
			buf := make([]byte, 4096)
			for {
				n, err := ptmx.Read(buf)
				if err != nil {
					sess.mu.Lock()
					if sess.conn != nil {
						sess.conn.Close()
					}
					sess.mu.Unlock()
					// Clean up session from registry
					ptySessionsMu.Lock()
					delete(ptySessions, sess.id)
					ptySessionsMu.Unlock()
					ptmx.Close()
					if cmd.Process != nil {
						cmd.Process.Kill()
						cmd.Process.Wait()
					}
					return
				}
				data := make([]byte, n)
				copy(data, buf[:n])
				sess.mu.Lock()
				sess.appendBuffer(data)
				sess.lastActivity = time.Now()
				if sess.conn != nil {
					if err := sess.conn.WriteMessage(websocket.BinaryMessage, data); err != nil {
						sess.conn = nil
					}
				}
				sess.mu.Unlock()
			}
		}()
	}

	// WebSocket → PTY
	for {
		msgType, msg, err := conn.ReadMessage()
		if err != nil {
			// Client disconnected — keep PTY alive for reconnection
			sess.mu.Lock()
			if sess.conn == conn {
				sess.conn = nil
				sess.lastActivity = time.Now()
			}
			sess.mu.Unlock()
			return
		}
		if msgType == websocket.TextMessage && strings.HasPrefix(string(msg), "resize:") {
			var size struct {
				Cols uint16 `json:"cols"`
				Rows uint16 `json:"rows"`
			}
			if err := json.Unmarshal(msg[7:], &size); err == nil {
				pty.Setsize(sess.ptmx, &pty.Winsize{Cols: size.Cols, Rows: size.Rows})
			}
			continue
		}
		sess.mu.Lock()
		sess.lastActivity = time.Now()
		sess.mu.Unlock()
		if _, err := sess.ptmx.Write(msg); err != nil {
			return
		}
	}
}

func handleTerminalSessions(w http.ResponseWriter, r *http.Request) {
	ptySessionsMu.Lock()
	list := make([]map[string]interface{}, 0, len(ptySessions))
	for _, s := range ptySessions {
		s.mu.Lock()
		connected := s.conn != nil
		list = append(list, map[string]interface{}{
			"id":            s.id,
			"name":          s.name,
			"created_at":    s.createdAt.Format(time.RFC3339),
			"last_activity": s.lastActivity.Format(time.RFC3339),
			"connected":     connected,
		})
		s.mu.Unlock()
	}
	ptySessionsMu.Unlock()
	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(list)
}

func handleTerminalSessionDelete(w http.ResponseWriter, r *http.Request) {
	id := r.URL.Query().Get("id")
	if id == "" {
		http.Error(w, "id required", http.StatusBadRequest)
		return
	}
	ptySessionsMu.Lock()
	sess, ok := ptySessions[id]
	if ok {
		delete(ptySessions, id)
	}
	ptySessionsMu.Unlock()
	if !ok {
		http.Error(w, "session not found", http.StatusNotFound)
		return
	}
	sess.mu.Lock()
	if sess.conn != nil {
		sess.conn.WriteMessage(websocket.TextMessage, []byte("\r\n\x1b[31m[会话已关闭]\x1b[0m\r\n"))
		sess.conn.Close()
		sess.conn = nil
	}
	sess.mu.Unlock()
	sess.ptmx.Close()
	if sess.cmd.Process != nil {
		sess.cmd.Process.Kill()
		sess.cmd.Process.Wait()
	}
	log.Printf("terminal session %s closed via API", id)
	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(map[string]bool{"ok": true})
}

func handleTerminalSessionRename(w http.ResponseWriter, r *http.Request) {
	var req struct {
		ID   string `json:"id"`
		Name string `json:"name"`
	}
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		http.Error(w, "invalid request", http.StatusBadRequest)
		return
	}
	if req.ID == "" || req.Name == "" {
		http.Error(w, "id and name required", http.StatusBadRequest)
		return
	}
	ptySessionsMu.Lock()
	sess, ok := ptySessions[req.ID]
	ptySessionsMu.Unlock()
	if !ok {
		http.Error(w, "session not found", http.StatusNotFound)
		return
	}
	sess.mu.Lock()
	sess.name = req.Name
	sess.mu.Unlock()
	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(map[string]bool{"ok": true})
}

func handleTerminalPage(w http.ResponseWriter, r *http.Request) {
	w.Header().Set("Content-Type", "text/html; charset=utf-8")
	w.Write([]byte(terminalPageHTML))
}

const terminalPageHTML = `<!DOCTYPE html>
<html lang="zh-CN">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Terminal</title>
<link rel="stylesheet" href="https://cdn.jsdelivr.net/npm/xterm@5.3.0/css/xterm.css">
<script src="https://cdn.jsdelivr.net/npm/xterm@5.3.0/lib/xterm.js"></script>
<script src="https://cdn.jsdelivr.net/npm/xterm-addon-fit@0.8.0/lib/xterm-addon-fit.js"></script>
<style>
* { margin: 0; padding: 0; box-sizing: border-box; }
body { background: #1e1e1e; overflow: hidden; }
#terminal-container { width: 100vw; height: 100vh; }
</style>
</head>
<body>
<div id="terminal-container"></div>
<script>
document.title = 'Terminal - ' + location.host;
const termFontSize = window.innerWidth <= 767 ? 12 : 14;
const term = new Terminal({ cursorBlink: true, fontSize: termFontSize, theme: { background: '#1e1e1e' } });
const fit = new FitAddon.FitAddon();
term.loadAddon(fit);
term.open(document.getElementById('terminal-container'));
fit.fit();

const proto = location.protocol === 'https:' ? 'wss:' : 'ws:';
const params = new URLSearchParams(location.search);
const sessionParam = params.get('session');
const wsUrl = proto + '//' + location.host + '/api/terminal' + (sessionParam ? '?session=' + sessionParam : '');
const ws = new WebSocket(wsUrl);
ws.binaryType = 'arraybuffer';

ws.onopen = function() {
  ws.send('resize:' + JSON.stringify({ cols: term.cols, rows: term.rows }));
};
ws.onmessage = function(e) {
  if (typeof e.data === 'string' && e.data.startsWith('session:')) {
    return;
  }
  if (e.data instanceof ArrayBuffer) {
    term.write(new Uint8Array(e.data));
  } else {
    term.write(e.data);
  }
};
ws.onclose = function() {
  term.write('\r\n\x1b[31m[连接已断开]\x1b[0m\r\n');
};
term.onData(function(data) {
  if (ws && ws.readyState === WebSocket.OPEN) {
    ws.send(new TextEncoder().encode(data));
  }
});
window.addEventListener('resize', function() {
  fit.fit();
  if (ws && ws.readyState === WebSocket.OPEN) {
    ws.send('resize:' + JSON.stringify({ cols: term.cols, rows: term.rows }));
  }
});
</script>
</body>
</html>`


func main() {
	dir := flag.String("dir", ".", "root directory to serve")
	port := flag.Int("port", 8080, "port to listen on")
	password := flag.String("password", "", "access password (empty = no auth)")
	flag.Parse()

	authPassword = *password

	absDir, err := filepath.Abs(*dir)
	if err != nil {
		log.Fatalf("invalid dir: %v", err)
	}
	// Resolve symlinks for rootDir so prefix checks work correctly
	absDir, err = filepath.EvalSymlinks(absDir)
	if err != nil {
		log.Fatalf("invalid dir: %v", err)
	}
	rootDir = absDir

	info, err := os.Stat(rootDir)
	if err != nil || !info.IsDir() {
		log.Fatalf("directory does not exist: %s", rootDir)
	}

	mux := http.NewServeMux()
	mux.HandleFunc("GET /", handleIndex)
	mux.HandleFunc("GET /terminal", handleTerminalPage)
	mux.HandleFunc("GET /api/files", handleFiles)
	mux.HandleFunc("POST /api/upload", handleUpload)
	mux.HandleFunc("POST /api/upload-folder", handleFolderUpload)
	mux.HandleFunc("GET /api/download", handleDownload)
	mux.HandleFunc("POST /api/delete", handleDelete)
	mux.HandleFunc("POST /api/rename", handleRename)
	mux.HandleFunc("POST /api/mkdir", handleMkdir)
	mux.HandleFunc("GET /api/read", handleRead)
	mux.HandleFunc("POST /api/save", handleSave)
	mux.HandleFunc("GET /api/terminal", handleTerminal)
	mux.HandleFunc("GET /api/terminal/sessions", handleTerminalSessions)
	mux.HandleFunc("DELETE /api/terminal/sessions", handleTerminalSessionDelete)
	mux.HandleFunc("POST /api/terminal/sessions/rename", handleTerminalSessionRename)
	mux.HandleFunc("POST /api/login", handleLogin)
	mux.HandleFunc("POST /api/logout", handleLogout)
	mux.HandleFunc("GET /api/auth-check", handleAuthCheck)

	addr := fmt.Sprintf(":%d", *port)
	srv := &http.Server{Addr: addr, Handler: logMiddleware(authMiddleware(mux))}

	mux.HandleFunc("POST /api/restart", func(w http.ResponseWriter, r *http.Request) {
		w.Header().Set("Content-Type", "application/json")
		json.NewEncoder(w).Encode(map[string]bool{"ok": true})
		log.Println("restart requested, rebuilding and restarting...")
		go func() {
			time.Sleep(500 * time.Millisecond)
			pid := fmt.Sprintf("%d", os.Getpid())
			exePath, _ := os.Executable()
			exeDir := filepath.Dir(exePath)
			cmd := exec.Command("bash", filepath.Join(exeDir, "restart_fileserver.sh"), pid,
				"-dir", *dir, "-port", fmt.Sprintf("%d", *port), "-password", *password)
			cmd.Dir = exeDir
			cmd.SysProcAttr = &syscall.SysProcAttr{Setsid: true}
			if err := cmd.Start(); err != nil {
				log.Printf("restart script start error: %v", err)
				return
			}
			srv.Shutdown(context.Background())
		}()
	})

	mux.HandleFunc("POST /api/shutdown", func(w http.ResponseWriter, r *http.Request) {
		w.Header().Set("Content-Type", "application/json")
		json.NewEncoder(w).Encode(map[string]bool{"ok": true})
		log.Println("shutdown requested, stopping server...")
		go func() {
			time.Sleep(500 * time.Millisecond)
			if err := srv.Shutdown(context.Background()); err != nil {
				log.Printf("shutdown error: %v", err)
			}
		}()
	})

	log.Printf("serving %s on http://0.0.0.0%s", rootDir, addr)
	if err := srv.ListenAndServe(); err != http.ErrServerClosed {
		log.Fatal(err)
	}
	log.Println("server stopped")
}
